import base64
import json
import logging
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define allowed task types and their handlers
ALLOWED_TASK_TYPES = {}

def register_task(task_type):
    """Decorator to register allowed task handlers."""
    def decorator(func):
        ALLOWED_TASK_TYPES[task_type] = func
        return func
    return decorator

@register_task("data_transform")
def handle_data_transform(payload):
    """Process a data transformation task."""
    input_data = payload.get("input_data", [])
    operation = payload.get("operation", "identity")
    logger.info(f"Processing data_transform: operation={operation}, items={len(input_data)}")
    return {"status": "completed", "processed_count": len(input_data)}

@register_task("aggregation")
def handle_aggregation(payload):
    """Process an aggregation task."""
    dataset_id = payload.get("dataset_id")
    aggregation_type = payload.get("aggregation_type", "sum")
    logger.info(f"Processing aggregation: dataset={dataset_id}, type={aggregation_type}")
    return {"status": "completed", "dataset_id": dataset_id}

@register_task("batch_notification")
def handle_batch_notification(payload):
    """Process a batch notification task."""
    recipients = payload.get("recipients", [])
    message_template = payload.get("template_id")
    logger.info(f"Processing notification: template={message_template}, recipients={len(recipients)}")
    return {"status": "completed", "notified_count": len(recipients)}


def validate_message(message_data):
    """Validate the structure of the incoming message."""
    required_fields = ["task_type", "task_id", "payload"]
    for field in required_fields:
        if field not in message_data:
            raise ValueError(f"Missing required field: {field}")

    task_type = message_data["task_type"]
    if task_type not in ALLOWED_TASK_TYPES:
        raise ValueError(f"Unknown task type: {task_type}. Allowed: {list(ALLOWED_TASK_TYPES.keys())}")

    return True


def process_pubsub_message(event, context):
    """
    Cloud Function entry point for processing Pub/Sub messages.

    Uses JSON deserialization (NOT pickle) for security.

    Args:
        event (dict): The Pub/Sub message event.
        context (google.cloud.functions.Context): The event context.
    """
    logger.info(f"Processing message ID: {context.event_id}, timestamp: {context.timestamp}")

    try:
        # Decode the Pub/Sub message data (base64 encoded)
        if "data" not in event:
            logger.error("No data field in Pub/Sub message")
            return

        raw_data = base64.b64decode(event["data"]).decode("utf-8")

        # SECURE: Use JSON deserialization instead of pickle
        # pickle.loads() is NEVER safe on untrusted input — it allows
        # arbitrary code execution during deserialization.
        message_data = json.loads(raw_data)

        # Validate message structure
        validate_message(message_data)

        task_type = message_data["task_type"]
        task_id = message_data["task_id"]
        payload = message_data["payload"]
        priority = message_data.get("priority", "normal")

        logger.info(f"Task received: id={task_id}, type={task_type}, priority={priority}")

        # Extract optional attributes from Pub/Sub message
        attributes = event.get("attributes", {})
        retry_count = int(attributes.get("retry_count", "0"))
        max_retries = int(attributes.get("max_retries", "3"))

        if retry_count > max_retries:
            logger.warning(f"Task {task_id} exceeded max retries ({max_retries}). Sending to dead letter.")
            return

        # Dispatch to the appropriate handler
        handler = ALLOWED_TASK_TYPES[task_type]
        result = handler(payload)

        logger.info(f"Task {task_id} completed successfully: {result}")

        return result

    except json.JSONDecodeError as e:
        logger.error(f"Failed to decode JSON message: {e}")
        raise
    except ValueError as e:
        logger.error(f"Message validation failed: {e}")
        raise
    except Exception as e:
        logger.error(f"Unexpected error processing message: {e}", exc_info=True)
        raise


# --- Helper for publishing tasks (for use by producers) ---

def create_task_message(task_type, task_id, payload, priority="normal"):
    """
    Create a properly formatted task message for publishing to Pub/Sub.

    Uses JSON serialization for safe, interoperable message encoding.

    Args:
        task_type: One of the registered task types.
        task_id: Unique identifier for this task.
        payload: Dictionary containing task-specific data.
        priority: Task priority level.

    Returns:
        bytes: Base64-encodable JSON bytes for Pub/Sub publishing.
    """
    if task_type not in ALLOWED_TASK_TYPES:
        raise ValueError(f"Unknown task type: {task_type}")

    message = {
        "task_type": task_type,
        "task_id": task_id,
        "payload": payload,
        "priority": priority,
        "created_at": datetime.utcnow().isoformat(),
    }

    # SECURE: JSON serialization — no arbitrary code execution risk
    return json.dumps(message).encode("utf-8")